import{_ as t,o as i,c as a,b as e,d as s,e as n,a as u,r as o}from"./app.b75dfbe6.js";var h="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/Gaestebuch1.jpg",p="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/Gaestebuch2.jpg",c="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/Gruppenfoto1.jpg",m="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/Gruppenfoto2.jpg",d="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/DOC-20260719-WA0033..jpg",l="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0013.jpg",g="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0014.jpg",k="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0015.jpg",_="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0016.jpg",f="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0017.jpg",v="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0018.jpg",M="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0019.jpg",b="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0020.jpg",w="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0021.jpg",S="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0022.jpg",P="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0023.jpg",G="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0024.jpg",Y="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0025.jpg",W="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0026.jpg",A="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0028.jpg",I="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0029.jpg",D="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0030.jpg",j="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0031.jpg",z="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0032.jpg",F="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/IMG-20260719-WA0036.jpg",T="/aktivitaeten/2026-07-19-Munich-Support-Your-Parks/Screenshot_potaapp.jpg";const L={},E=e("h1",{id:"bericht-support-your-parks-weekend-sommer-2026-munchen",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#bericht-support-your-parks-weekend-sommer-2026-munchen","aria-hidden":"true"},"#"),n(" Bericht Support Your Parks Weekend Sommer 2026 M\xFCnchen")],-1),B=e("p",null,"Am 19. Juli um 11:00 Uhr K\xFCchenzeit war es so weit. Einige Draussenfunker aus M\xFCnchen und aus dem M\xFCnchner Umland haben sich im Landschaftspark Hachinger Tal (POTA-Referenz DE-0546) zum sommerlichen Support Your Parks Weekend getroffen.",-1),R=e("p",null,"Zuerst hatte es jedoch den Anschein, dass durch das Wetter dem Funkertreffen ein nasser und gewittriger Strich durch die Rechnung gemacht wird. Ein fr\xFChmorgendlicher Blick aus einem Unterhachinger Fenster hat einen bew\xF6lkten Himmel und ausdauernden Landregen gezeigt. Der darauffolgende Blick auf den Wetterbericht hat f\xFCr den Landschaftspark tags\xFCber ergiebige Regenschauer mit Gewitter vorhergesagt. Die Wetterg\xF6tter waren dem Treffen jedoch gn\xE4dig gestimmt und um etwa 10:00 Uhr ist der Himmel aufgeklart und die Wetterprognose hat sich dann ebenfalls sehr z\xFCgig in Wohlgefallen aufgel\xF6st. Bei angenehmen 20 Grad Celsius hat sich w\xE4hrend des Teffens wundersch\xF6ner Sonnenschein mit leichter Bew\xF6lkung abgewechselt und damit herrlich angenehmes Draussenfunkwetter beschert.",-1),H=n("Bereits um 11:00 Uhr war das Gros der Teilnehmer am Treffpunkt eingetroffen und es wurde mit dem gemeinsamen Aufbau der mitgebrachten Antennen begonnen. Neben einigen Vertikalantennen war eine EFRW mitsamt 1:9-UnUn und 10 Meter Draht gewickelt um einen 12 Meter Spiderbeam, eine T2FD an einem 10-Meter-Mast und eine EFHW mit circa 20 Meter Draht aufgebaut als Inverted-V an einem 7-Meter-Spiderbeam in Verwendung. An den Antennen werkelten neben einen Lab599 TX-500 mehrere klassische Draussenfunkerarbeitspferde vom Typ Yaesu FT-891 und Icom IC-705. Ein Highlight war auch ein Elecraft KH1 der abwechselnd an einer kleinen am Busch h\xE4ngenden Randomwireantenne, an der obig erw\xE4hnten 10 Meter EFRW und mit der integrierten Teleskopantenne betrieben wurde. Auf jeden Fall sollen auch noch die zahlreich vorhandenen Handfunkger\xE4te f\xFCr 2 m und 70 cm nicht unerw\xE4hnt bleiben, die diese zu zahlreichen lokalen Park-to-Park-Verbindungen verholfen haben. Diese Park-To-Park-Verbindungen waren teilweise auch notwendig, da durch den gleichzeitigen Betrieb mehrerer Funkstationen in unmittelbarer Nachbarschaft die Frequenzauswahl etwas eingeschr\xE4nkt war. Zus\xE4tzlich haben die Funkwetterbedingungen die Aktivierungen ebenfalls etwas erschwert. Hier kamen dann die lokalen Park-to-Park-QSOs auf 2 m und 70 cm wie gerufen, um die "),U={href:"https://pota.app/#/park/DE-0546",target:"_blank",rel:"noopener noreferrer"},V=n("POTA-Aktivierungen"),x=n(" erfolgreich abzuschlie\xDFen."),N=u('<p>W\xE4hrend des Treffens war ein stetiges Kommen und Gehen von interessierten YLs, OMs und SWLs zu verzeichnen, welche flei\xDFig Funkbetrieb an einer der aufgebauten Stationen gemacht haben. Neben dem Funken kamen das Fachsimpeln und der allgemeine gesellige Austausch ebenfalls nicht zu kurz. Als sich das Treffen nach dem Abbau des Equipments gegen 17:00 Uhr dem Ende zugeneigt hat, sind auch sogleich die ersten Regen- und Gewitterwolken aufgezogen, um den noch verbliebenen Personenkreis eine nassk\xFChle Dusche zu bereiten. Alles in allem war es ein sehr sch\xF6nes Treffen mit netten und interessanten Gespr\xE4chen sowie einen einstimmigen Tenor, dass im Herbst zum n\xE4chsten Support Your Parks Weekend wieder ein Treffen in einem der M\xFCnchner Parks stattfinden soll.</p><p>Eine tolle Idee von Rosi DG5YL war das G\xE4stebuch, in dem sich die anwesenden Besucher verewigen konnten.</p><p><img src="'+h+'" alt=""><img src="'+p+'" alt=""></p><p>Ein Gruppenfoto mit einem Teil der Teilnehmer (v.l.n.r Wolfgang DL1MIE, Frank DG0WOL, Rosi DG5YL, Markus DG6LP, Julian DD4JS, Reinhard DC1YY, Ingolf DL2HIR, Iman SWL und angehender Funkamateur). Die anderen nicht auf dem Bild befindlichen Teilnehmer waren vertieft im Funkflow und haben das Happening zum Gruppenfoto teilweise gar nicht mitbekommen.</p><p><img src="'+c+'" alt=""></p><p>Ein weiteres Gruppenfoto mit leicht ver\xE4nderter Personenkonstellation, um auch den Fotografen des vorherigen Schnappschusses auf das Bild zu bekommen (v.l.n.r Max DH1MFS, Wolfgang DL1MIE, Frank DG0WOL, Rosi DG5YL, Markus DG6LP, Julian DD4JS, Reinhard DC1YY, Ingolf DL2HIR). Auch hier war wieder ein Teil der Funkamateure dem Funkfieber (tm) verfallen und haben das Fotoshooting verpasst.</p><p><img src="'+m+'" alt=""></p><p>Und hier noch einige abschlie\xDFende Impressionen zum Draussenfunkertreffen.</p><p><img src="'+d+'" alt=""><img src="'+l+'" alt=""><img src="'+g+'" alt=""><img src="'+k+'" alt=""><img src="'+_+'" alt=""><img src="'+f+'" alt=""><img src="'+v+'" alt=""><img src="'+M+'" alt=""><img src="'+b+'" alt=""><img src="'+w+'" alt=""><img src="'+S+'" alt=""><img src="'+P+'" alt=""><img src="'+G+'" alt=""><img src="'+Y+'" alt=""><img src="'+W+'" alt=""><img src="'+A+'" alt=""><img src="'+I+'" alt=""><img src="'+D+'" alt=""><img src="'+j+'" alt=""><img src="'+z+'" alt=""><img src="'+F+'" alt=""><img src="'+T+'" alt=""></p>',9);function O(C,J){const r=o("ExternalLinkIcon");return i(),a("div",null,[E,B,R,e("p",null,[H,e("a",U,[V,s(r)]),x]),N])}var K=t(L,[["render",O],["__file","2026-07-19-Bericht-Support-Your-Parks-Muenchen.html.vue"]]);export{K as default};
